diff --git a/src/njs_vmcode.c b/src/njs_vmcode.c
index ec47865..36d9138 100644
--- a/src/njs_vmcode.c
+++ b/src/njs_vmcode.c
@@ -797,8 +797,35 @@ next:
                 pnext = (njs_vmcode_prop_next_t *) pc;
                 retval = njs_scope_value(vm, pnext->retval);

+                /* Ensure that the operand is a data value carrying the
+                 * iterator.  Previous code assumed the slot was vm->retval
+                 * which could be overwritten by await.  Now the iterator
+                 * is stored in a scope slot, but still validate the type
+                 * to avoid crashes if invariants are broken. */
+                if (njs_slow_path(value2->type != NJS_DATA)) {
+                    njs_set_undefined(retval);
+                    ret = sizeof(njs_vmcode_prop_next_t);
+                    break;
+                }
+
                 next = value2->data.u.next;

+                if (njs_slow_path(next == NULL)) {
+                    njs_set_undefined(retval);
+                    ret = sizeof(njs_vmcode_prop_next_t);
+                    break;
+                }
+
+                if (next->array == NULL || next->array->start == NULL) {
+                    /* Cleanup the iterator slot to avoid future deref. */
+                    njs_mp_free(vm->mem_pool, next);
+                    njs_set_invalid(njs_scope_value(vm, pnext->next));
+
+                    njs_set_undefined(retval);
+                    ret = sizeof(njs_vmcode_prop_next_t);
+                    break;
+                }
+
                 if (next->index < next->array->length) {
                     *retval = next->array->start[next->index++];

@@ -806,7 +833,9 @@ next:
                     break;
                 }

+                /* End of iteration: free iterator and clear the slot. */
                 njs_mp_free(vm->mem_pool, next);
+                njs_set_invalid(njs_scope_value(vm, pnext->next));

                 ret = sizeof(njs_vmcode_prop_next_t);
                 break;
@@ -1430,10 +1459,23 @@ njs_vmcode_property_foreach(njs_vm_t *vm, njs_value_t *object,
         return NJS_ERROR;
     }

-    vm->retval.data.u.next = next;
-
+    /* Store the iterator in a stable scope slot so it survives across
+     * async suspension and resume.  vm->retval is volatile and can be
+     * overwritten by await/resume.  Use njs_set_data to fully initialize
+     * the tagged value that carries the iterator pointer. */
     code = (njs_vmcode_prop_foreach_t *) pc;

+    {
+        njs_value_t *slot = njs_scope_value(vm, code->next);
+
+        if (njs_slow_path(slot == NULL)) {
+            njs_memory_error(vm);
+            return NJS_ERROR;
+        }
+
+        njs_set_data(slot, next, NJS_DATA_TAG_ANY);
+    }
+
     return code->offset;
 }

diff --git a/src/class.c b/src/class.c
index ec9c648..a679ec2 100644
--- a/src/class.c
+++ b/src/class.c
@@ -357,7 +357,9 @@ prepare_singleton_class(mrb_state *mrb, struct RBasic *o)
 {
   struct RClass *sc, *c;

-  if (o->c->tt == MRB_TT_SCLASS) return;
+  /* If object already has singleton class, nothing to do. Guard against
+     o->c being NULL (e.g. some Proc objects) before dereferencing. */
+  if (o->c && o->c->tt == MRB_TT_SCLASS) return;
   sc = MRB_OBJ_ALLOC(mrb, MRB_TT_SCLASS, mrb->class_class);
   sc->flags |= MRB_FL_CLASS_IS_INHERITED;
   sc->mt = mt_new(mrb);
@@ -368,18 +370,37 @@ prepare_singleton_class(mrb_state *mrb, struct RBasic *o)
       sc->super = mrb->class_class;
     }
     else {
-      sc->super = c->super->c;
+      sc->super = c->super->c ? c->super->c : mrb->class_class;
     }
   }
   else if (o->tt == MRB_TT_SCLASS) {
     c = (struct RClass*)o;
-    while (c->super->tt == MRB_TT_ICLASS)
+    while (c->super && c->super->tt == MRB_TT_ICLASS)
       c = c->super;
-    make_metaclass(mrb, c->super);
-    sc->super = c->super->c;
+    if (c->super == NULL) {
+      sc->super = mrb->class_class;
+    }
+    else {
+      make_metaclass(mrb, c->super);
+      sc->super = c->super->c ? c->super->c : mrb->class_class;
+    }
   }
   else {
-    sc->super = o->c;
+    /* For regular objects, use object's class as super if available. Some
+       object types (e.g. Proc) may have o->c == NULL; handle that case by
+       using the proc's target class or a sensible default. */
+    if (o->c) {
+      sc->super = o->c;
+    }
+    else if (o->tt == MRB_TT_PROC) {
+      struct RProc *p = (struct RProc*)o;
+      struct RClass *tc = MRB_PROC_TARGET_CLASS(p);
+
+      sc->super = tc ? tc : mrb->class_class;
+    }
+    else {
+      sc->super = mrb->class_class;
+    }
     prepare_singleton_class(mrb, (struct RBasic*)sc);
   }
   o->c = sc;

