+  slen = strlen(src);
+  /* Worst-case expansion: each input byte may expand up to 6 bytes (e.g. " -> &quot;). */
+  size_t len = slen * 6 + 1;
+  dest = malloc(len);
+  if (!dest)
+    return NULL;
+  s = (const unsigned char *)src;
+  d = dest;
+
+  /* Start with empty string and use d as pointer to the end. */
+  d[0] = '\0';
+  char *out = d;
+  unsigned char c;
+
+  while ((c = *s++) != 0)
     {
-      const int off = d - dest;
-      if (off >= len - 8)
+      size_t off = out - dest;
+      if (off + 8 >= len)
         {
-          len += 10;
-          dest = realloc (dest, len);
-          d = dest + off;
+          /* grow buffer by doubling to accommodate future expansions */
+          size_t newlen = len * 2;
+          if (newlen <= len) /* overflow */
+            return dest; /* return what we have */
+          char *tmp = realloc(dest, newlen);
+          if (!tmp)
+            return dest; /* on allocation failure return current buffer */
+          dest = tmp;
+          out = dest + off;
+          len = newlen;
         }
-      switch (*s)
+
+      switch (c)
         {
-        case '"': strcat (d, "&quot;"); d += 6; break;
-        case '\'': strcat (d, "&#39;"); d += 5; break;
-        case '`': strcat (d, "&#96;"); d += 5; break;
-        case '&': strcat (d, "&amp;"); d += 5; break;
-        case '<': strcat (d, "&lt;"); d += 4; break;
-        case '>': strcat (d, "&gt;"); d += 4; break;
-        case '{': strcat (d, "&#123;"); d += 6; break;
-        case '}': strcat (d, "&#125;"); d += 6; break;
+        case '"': memcpy(out, "&quot;", 6); out += 6; break;
+        case '\'': memcpy(out, "&#39;", 5); out += 5; break;
+        case '`': memcpy(out, "&#96;", 5); out += 5; break;
+        case '&': memcpy(out, "&amp;", 5); out += 5; break;
+        case '<': memcpy(out, "&lt;", 4); out += 4; break;
+        case '>': memcpy(out, "&gt;", 4); out += 4; break;
+        case '{': memcpy(out, "&#123;", 6); out += 6; break;
+        case '}': memcpy(out, "&#125;", 6); out += 6; break;
         default:
-          if (*s >= 127) // maybe encodings, no utf8 (see htmlwescape)
+          if (c >= 127) /* maybe encodings, no utf8 (see htmlwescape) */
             {
-              sprintf (d, "&#x%X;", *s); // 4 + 4
-              d += strlen (d);
+              int n = sprintf(out, "&#x%X;", c); /* writes terminating NUL */
+              out += n;
             }
-          else if (*s >= 20)
-            *d++ = *s;
+          else if (c >= 20)
+            *out++ = c;
         }
     }
-  *d = 0;
+  *out = '\0';
   return dest;
 }

