diff --git a/libarchive/archive_read_support_format_lha.c b/libarchive/archive_read_support_format_lha.c
index b8ef4ae..04ce1bf 100644
--- a/libarchive/archive_read_support_format_lha.c
+++ b/libarchive/archive_read_support_format_lha.c
@@ -1411,6 +1411,16 @@ lha_read_data_none(struct archive_read *a, const void **buff,
 		lha->end_of_entry = 1;
 		return (ARCHIVE_OK);
 	}
+	/* If entry_bytes_remaining is negative, treat this as truncated/corrupt.
+	 * This prevents a negative value from being used in unsigned contexts
+	 * and avoids a potential large unsigned length being passed to
+	 * lha_crc16().
+	 */
+	if (lha->entry_bytes_remaining < 0) {
+		archive_set_error(&a->archive, ARCHIVE_ERRNO_FILE_FORMAT,
+		    "Truncated LHa file data");
+		return (ARCHIVE_FATAL);
+	}
 	/*
 	 * Note: '1' here is a performance optimization.
 	 * Recall that the decompression layer returns a count of
@@ -1494,6 +1504,14 @@ lha_read_data_lzh(struct archive_read *a, const void **buff,
 		    "Truncated LHa file body");
 		return (ARCHIVE_FATAL);
 	}
+	/* Protect against negative remaining size which could lead to
+	 * signed-to-unsigned conversion issues when assigned to bytes_avail.
+	 */
+	if (lha->entry_bytes_remaining < 0) {
+		archive_set_error(&a->archive, ARCHIVE_ERRNO_FILE_FORMAT,
+		    "Truncated LHa file data");
+		return (ARCHIVE_FATAL);
+	}
 	if (bytes_avail > lha->entry_bytes_remaining)
 		bytes_avail = (ssize_t)lha->entry_bytes_remaining;

diff --git a/src/isomedia/box_code_base.c b/src/isomedia/box_code_base.c
