 	GF_SAFEALLOC(def_ptr, GF_DefaultSampleGroupDescriptionEntry);
 	if (!def_ptr) return NULL;
 	if (entry_size) {
+		/* ensure the declared entry_size fits in the remaining box bytes */
+		if (bytes_in_box < (s32)entry_size) {
+			gf_free(def_ptr);
+			GF_LOG(GF_LOG_ERROR, GF_LOG_CONTAINER, ("[iso file] sgpd entry size %u exceeds remaining box bytes %d\n", entry_size, bytes_in_box));
+			return NULL;
+		}
 		def_ptr->length = entry_size;
 		def_ptr->data = (u8 *) gf_malloc(sizeof(u8)*def_ptr->length);
 		if (!def_ptr->data) {
@@ -10243,21 +10249,47 @@ GF_Err sgpd_box_read(GF_Box *s, GF_BitStream *bs)
 		ISOM_DECREASE_SIZE(p, 4);
 		p->default_description_index = gf_bs_read_u32(bs);
 	}
+	/* entry_count is 4 bytes */
+	ISOM_DECREASE_SIZE(p, 4);
 	entry_count = gf_bs_read_u32(bs);

-	if (entry_count>p->size)
-		return GF_ISOM_INVALID_FILE;
+	/* basic validation: ensure declared entry_count cannot overflow remaining box bytes
+	   account for per-entry size fields when default_length==0 (each entry has a 4-byte length)
+	*/
+	u32 min_entry_size = 0;
+	if (p->version>=1) {
+		/* if default_length is zero, each entry will have a 4-byte length field; otherwise each entry is at least default_length bytes */
+		min_entry_size = (p->default_length == 0) ? 4 : p->default_length;
+	}
+	if (min_entry_size) {
+		/* protect against multiplication overflow */
+		if ((u64)entry_count > (u64)SIZE_MAX / (u64)min_entry_size) {
+			GF_LOG(GF_LOG_ERROR, GF_LOG_CONTAINER, ("[iso file] Invalid entry_count %u in sgpd (overflow)\n", entry_count));
+			return GF_ISOM_INVALID_FILE;
+		}
+		if ((u64)entry_count * (u64)min_entry_size > (u64)p->size) {
+			GF_LOG(GF_LOG_ERROR, GF_LOG_CONTAINER, ("[iso file] Invalid entry_count %u in sgpd (box size %u)\n", entry_count, p->size));
+			return GF_ISOM_INVALID_FILE;
+		}
+	}

 	while (entry_count) {
 		void *ptr;
 		u32 parsed_bytes=0;
 		u32 size = p->default_length;
 		if ((p->version>=1) && !size) {
+			/* per-entry size field: ensure we have enough bytes to read it */
+			if (p->size < 4) return GF_ISOM_INVALID_FILE;
 			size = gf_bs_read_u32(bs);
 			ISOM_DECREASE_SIZE(p, 4);
 		}
+		/* sanity: declared entry size must fit into remaining box bytes */
+		if (size > p->size) {
+			GF_LOG(GF_LOG_ERROR, GF_LOG_CONTAINER, ("[iso file] Declared sgpd entry size %u larger than remaining box size %u\n", size, p->size));
+			return GF_ISOM_INVALID_FILE;
+		}
 		ptr = sgpd_parse_entry(p->grouping_type, bs, (s32) p->size, size, &parsed_bytes);
-		//don't return an error, just stop parsing so that we skip over the sgpd box
+		/* if parsing of this entry failed, stop parsing the box to avoid inconsistent state */
 		if (!ptr) return GF_OK;
 		gf_list_add(p->group_descriptions, ptr);

@@ -10299,15 +10331,16 @@ GF_Err sgpd_box_size(GF_Box *s)
 	Bool use_def_size = GF_TRUE;
 	GF_SampleGroupDescriptionBox *p = (GF_SampleGroupDescriptionBox *)s;

-	p->size += 8;
-
+	/* header size already initialized by gf_isom_box_size_listing (8 bytes) */
 	//we force all sample groups to version 1, v0 being deprecated
 	if (!p->version)
 		p->version = 1;
-	p->size += 4;
+	/* grouping_type + default_length (version>=1) */
+	p->size += 4; /* grouping_type */
+	p->size += 4; /* default_length (version 1 present by default) */

 	if (p->version>=2)
-		p->size += 4;
+		p->size += 4; /* default_description_index */
 	p->default_length = 0;

 	nb_descs = gf_list_count(p->group_descriptions);
